commit 64ed699b3d811407e5a9f1111f63e11dc7f7dd80
Author: DianQK <dianqk@dianqk.net>
Date:   Wed Jan 3 09:22:13 2024 +0800

    Reland "[SimplifyCFG] When only one case value is missing, replace default with that case (#76669)"

    When the default branch is the last case, we can transform that branch
    into a concrete branch with an unreachable default branch.

    ```llvm
    target datalayout = "e-m:e-p270:32:32-p271:32:32-p272:64:64-i64:64-f80:128-n8:16:32:64-S128"
    target triple = "x86_64-unknown-linux-gnu"

    define i64 @src(i64 %0) {
      %2 = urem i64 %0, 4
      switch i64 %2, label %5 [
        i64 1, label %3
        i64 2, label %3
        i64 3, label %4
      ]

    3:                                                ; preds = %1, %1
      br label %5

    4:                                                ; preds = %1
      br label %5

    5:                                                ; preds = %1, %4, %3
      %.0 = phi i64 [ 2, %4 ], [ 1, %3 ], [ 0, %1 ]
      ret i64 %.0
    }

    define i64 @tgt(i64 %0) {
      %2 = urem i64 %0, 4
      switch i64 %2, label %unreachable [
        i64 0, label %5
        i64 1, label %3
        i64 2, label %3
        i64 3, label %4
      ]

    unreachable:                              ; preds = %1
      unreachable

    3:                                                ; preds = %1, %1
      br label %5

    4:                                                ; preds = %1
      br label %5

    5:                                                ; preds = %1, %4, %3
      %.0 = phi i64 [ 2, %4 ], [ 1, %3 ], [ 0, %1 ]
      ret i64 %.0
    }
    ```

    Alive2: https://alive2.llvm.org/ce/z/Y-PGXv

    After transform to a lookup table, I believe `tgt` is better code.

    The final instructions are as follows:

    ```asm
    src:                                    # @src
            and     edi, 3
            lea     rax, [rdi - 1]
            cmp     rax, 2
            ja      .LBB0_1
            mov     rax, qword ptr [8*rdi + .Lswitch.table.src-8]
            ret
    .LBB0_1:
            xor     eax, eax
            ret
    tgt:                                    # @tgt
            and     edi, 3
            mov     rax, qword ptr [8*rdi + .Lswitch.table.tgt]
            ret
    .Lswitch.table.src:
            .quad   1                               # 0x1
            .quad   1                               # 0x1
            .quad   2                               # 0x2

    .Lswitch.table.tgt:
            .quad   0                               # 0x0
            .quad   1                               # 0x1
            .quad   1                               # 0x1
            .quad   2                               # 0x2
    ```

    Godbolt: https://llvm.godbolt.org/z/borME8znd

    Closes #73446.

    (cherry picked from commit 7d81e072712f4e6a150561b5538ccebda289aa13)

diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 93701b2a7791..4cbe7159651a 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5501,11 +5501,13 @@ static bool CasesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
 }

 static void createUnreachableSwitchDefault(SwitchInst *Switch,
-                                           DomTreeUpdater *DTU) {
+                                           DomTreeUpdater *DTU,
+                                           bool RemoveOrigDefaultBlock = true) {
   LLVM_DEBUG(dbgs() << "SimplifyCFG: switch default is dead.\n");
   auto *BB = Switch->getParent();
   auto *OrigDefaultBlock = Switch->getDefaultDest();
-  OrigDefaultBlock->removePredecessor(BB);
+  if (RemoveOrigDefaultBlock)
+    OrigDefaultBlock->removePredecessor(BB);
   BasicBlock *NewDefaultBlock = BasicBlock::Create(
       BB->getContext(), BB->getName() + ".unreachabledefault", BB->getParent(),
       OrigDefaultBlock);
@@ -5514,7 +5516,8 @@ static void createUnreachableSwitchDefault(SwitchInst *Switch,
   if (DTU) {
     SmallVector<DominatorTree::UpdateType, 2> Updates;
     Updates.push_back({DominatorTree::Insert, BB, &*NewDefaultBlock});
-    if (!is_contained(successors(BB), OrigDefaultBlock))
+    if (RemoveOrigDefaultBlock &&
+        !is_contained(successors(BB), OrigDefaultBlock))
       Updates.push_back({DominatorTree::Delete, BB, &*OrigDefaultBlock});
     DTU->applyUpdates(Updates);
   }
@@ -5696,10 +5699,28 @@ static bool eliminateDeadSwitchCases(SwitchInst *SI, DomTreeUpdater *DTU,
       Known.getBitWidth() - (Known.Zero | Known.One).popcount();
   assert(NumUnknownBits <= Known.getBitWidth());
   if (HasDefault && DeadCases.empty() &&
-      NumUnknownBits < 64 /* avoid overflow */ &&
-      SI->getNumCases() == (1ULL << NumUnknownBits)) {
-    createUnreachableSwitchDefault(SI, DTU);
-    return true;
+      NumUnknownBits < 64 /* avoid overflow */) {
+    uint64_t AllNumCases = 1ULL << NumUnknownBits;
+    if (SI->getNumCases() == AllNumCases) {
+      createUnreachableSwitchDefault(SI, DTU);
+      return true;
+    }
+    // When only one case value is missing, replace default with that case.
+    // Eliminating the default branch will provide more opportunities for
+    // optimization, such as lookup tables.
+    if (SI->getNumCases() == AllNumCases - 1) {
+      assert(NumUnknownBits > 1 && "Should be canonicalized to a branch");
+      uint64_t MissingCaseVal = 0;
+      for (const auto &Case : SI->cases())
+        MissingCaseVal ^= Case.getCaseValue()->getValue().getLimitedValue();
+      auto *MissingCase =
+          cast<ConstantInt>(ConstantInt::get(Cond->getType(), MissingCaseVal));
+      SwitchInstProfUpdateWrapper SIW(*SI);
+      SIW.addCase(MissingCase, SI->getDefaultDest(), SIW.getSuccessorWeight(0));
+      createUnreachableSwitchDefault(SI, DTU, /*RemoveOrigDefaultBlock*/ false);
+      SIW.setSuccessorWeight(0, 0);
+      return true;
+    }
   }

   if (DeadCases.empty())

tests.expect_optimized_program:
target datalayout = "e-m:e-p270:32:32-p271:32:32-p272:64:64-i64:64-f80:128-n8:16:32:64-S128"

@switch.table.test_1 = private unnamed_addr constant [4 x i64] [i64 0, i64 1, i64 1, i64 2], align 8

define i64 @test_1(i64 %0) {
switch.lookup:
  %1 = urem i64 %0, 4
  %switch.gep = getelementptr inbounds [4 x i64], ptr @switch.table.test_1, i32 0, i64 %1
  %switch.load = load i64, ptr %switch.gep, align 8
  ret i64 %switch.load
}
